void ZopfliBlockSplitLZ77(const ZopfliOptions *options,
                          const ZopfliLZ77Store *lz77, size_t maxblocks,
                          size_t **splitpoints, size_t *npoints)
/* NOTE (CBMC): the loop body is unreachable under any SOUND callee-contract
 * setup.  Reaching it requires lz77->size >= 10 (to skip the early return), but
 * the contracts of the callees it must invoke pin the opposite regime:
 * EstimateCost requires lz77->size <= 3 and FindLargestSplittableBlock requires
 * lz77size <= 6.  Those callees cannot be inlined instead (FindMinimum's
 * function-pointer body recurses through BoundaryPM and aborts goto-instrument;
 * EstimateCost forwards to the full ZopfliCalculateBlockSizeAutoType tree).  So
 * the only verifiable regime is the early return (lz77->size < 10), where the
 * function does nothing.  The contract below is the strongest SOUND spec for
 * that regime; the three entry-guard mutants that flip lz77->size < 10 so the
 * mutant enters the loop are killed (the loop body fails a callee precondition),
 * while the != variant and every in-loop mutant are inherently vacuous here. */
__CPROVER_requires(__CPROVER_is_fresh(lz77, sizeof(*lz77)))
__CPROVER_requires(lz77->size < 10)
__CPROVER_assigns()
{
    size_t lstart, lend;
    size_t i;
    size_t llpos = 0;
    size_t numblocks = 1;
    unsigned char *done;
    double splitcost, origcost;

    if (lz77->size < 10)
        return; /* This code fails on tiny files. */

    done = (unsigned char *)malloc(lz77->size);
    if (!done)
        exit(-1); /* Allocation failed. */
    for (i = 0; i < lz77->size; i++)
        done[i] = 0;

    lstart = 0;
    lend = lz77->size;
    for (;;)
    {
        SplitCostContext c;

        if (maxblocks > 0 && numblocks >= maxblocks)
        {
            break;
        }

        c.lz77 = lz77;
        c.start = lstart;
        c.end = lend;
        assert(lstart < lend);
        llpos = FindMinimum(SplitCost, &c, lstart + 1, lend, &splitcost);

        assert(llpos > lstart);
        assert(llpos < lend);

        origcost = EstimateCost(lz77, lstart, lend);

        if (splitcost > origcost || llpos == lstart + 1 || llpos == lend)
        {
            done[lstart] = 1;
        }
        else
        {
            AddSorted(llpos, splitpoints, npoints);
            numblocks++;
        }

        if (!FindLargestSplittableBlock(
                lz77->size, done, *splitpoints, *npoints, &lstart, &lend))
        {
            break; /* No further split will probably reduce compression. */
        }

        if (lend - lstart < 10)
        {
            break;
        }
    }

    if (options->verbose)
    {
        PrintBlockSplitPoints(lz77, *splitpoints, *npoints);
    }

    free(done);
}

